select.foreach:
(
    SELECT item_id, nft_id, image_url
    FROM bili_nft_detail
    WHERE item_id = #{itemId}
      AND image_url IS NOT NULL
      AND image_url != ''
    ORDER BY RAND()
    LIMIT #{limit}
)
